import { pluginName } from './constants';

const { CKEDITOR } = window;

/*
 * CKEditor 4 colour‑apply / remove plugin
 */
CKEDITOR.plugins.add(pluginName, {
  requires: 'richcombo',
  init(editor) {
    const colorMap = CKEDITOR.tools.get_plugin_config(pluginName, editor);

    /* ------------------------------ utils ------------------------------ */
    const utils = {
      clone(el) {
        const copy = new CKEDITOR.dom.element(el.getName());
        Object.entries(el.getAttributes()).forEach(([k, v]) => copy.setAttribute(k, v));
        return copy;
      },
      wrapInside(node, chain) {
        return chain.reduceRight((inner, outer) => {
          const wrapper = utils.clone(outer);
          wrapper.append(inner);
          return wrapper;
        }, node);
      }
    };

    /* ---------------- span‑lifter ---------------- */
    function liftColorSpans(range) {
      const walkRange = range.clone();
      walkRange.enlarge(CKEDITOR.ENLARGE_INLINE);
    
      const walker = new CKEDITOR.dom.walker(walkRange);
      walker.evaluator = n =>
        n &&
        n.type === CKEDITOR.NODE_ELEMENT &&
        n.getName() === 'span' &&
        n.getStyle('color');
    
      let span;
      while ((span = walker.next())) {
        const parent = span.getParent();
        if (!parent) continue;
        console.log('Lifting span from parent hasmik', parent.getName());
        const parentName = parent.getName();
    
        // Only lift through inline elements.
        // Never wrap block elements like <p>, <div>, <li>, etc inside <span>.
        if (!CKEDITOR.dtd.$inline[parentName] || parentName === 'span') {
          continue;
        }
    
        const firstChild = span.getFirst();
        if (
          firstChild &&
          firstChild.type === CKEDITOR.NODE_ELEMENT &&
          firstChild.getName() === parentName
        ) {
          continue;
        }
    
        const clone = utils.clone(parent);
        while (span.getFirst()) {
          clone.append(span.getFirst().remove());
        }
        span.append(clone);
      }
    }

    function splitMixedBoundarySelection(range) {
      const startSpan = range.startContainer.getAscendant('span', true);
      const endSpan = range.endContainer.getAscendant('span', true);
      console.log('split hasmik');
      const startColorSpan = startSpan && startSpan.getStyle('color') ? startSpan : null;
      const endColorSpan = endSpan && endSpan.getStyle('color') ? endSpan : null;
    
      /* Case 1:
         selection starts OUTSIDE color span and ends INSIDE color span
         => remove color from beginning of that span up to endOffset
      */
      if (!startColorSpan && endColorSpan && range.endContainer.type === CKEDITOR.NODE_TEXT) {
        const textNode = range.endContainer;
        const colorSpan = endColorSpan;
        const fullText = textNode.getText();
    
        const selected = fullText.slice(0, range.endOffset);
        const after = fullText.slice(range.endOffset);
    
        if (selected) {
          colorSpan.insertBeforeMe(new CKEDITOR.dom.text(selected));
        }
    
        if (after) {
          const spanCopy = utils.clone(colorSpan);
          spanCopy.append(new CKEDITOR.dom.text(after));
          colorSpan.insertBeforeMe(spanCopy);
        }
    
        textNode.remove();
    
        if (!colorSpan.getChildCount()) {
          colorSpan.remove();
        }
    
        return true;
      }
    
      /* Case 2:
         selection starts INSIDE color span and ends OUTSIDE color span
         => remove color from startOffset to end of that span
      */
      if (startColorSpan && !endColorSpan && range.startContainer.type === CKEDITOR.NODE_TEXT) {
        const textNode = range.startContainer;
        const colorSpan = startColorSpan;
        const fullText = textNode.getText();
    
        const before = fullText.slice(0, range.startOffset);
        const selected = fullText.slice(range.startOffset);
    
        if (before) {
          const spanCopy = utils.clone(colorSpan);
          spanCopy.append(new CKEDITOR.dom.text(before));
          colorSpan.insertBeforeMe(spanCopy);
        }
    
        if (selected) {
          colorSpan.insertBeforeMe(new CKEDITOR.dom.text(selected));
        }
    
        textNode.remove();
    
        if (!colorSpan.getChildCount()) {
          colorSpan.remove();
        }
    
        return true;
      }
    
      return false;
    }

    /* -------------- colour remover  -------------- */
    function smartRemoveColorFromPartial(range) {

      /* ---------- Pass 1 – full-span selection ----------------- */
      const spanAncestor = range.startContainer.getAscendant('span', true);
    
      const isSpan = spanAncestor && spanAncestor.getStyle('color');
      const containsStart = spanAncestor && range.checkBoundaryOfElement(spanAncestor, CKEDITOR.START);
      const containsEnd =
        spanAncestor &&
        (
          range.checkBoundaryOfElement(spanAncestor, CKEDITOR.END) ||
          (range.endContainer.equals(spanAncestor) && range.endOffset === 0)
        );
    
      const spanIsFullyCovered = isSpan && containsStart && containsEnd;
    
      if (spanIsFullyCovered) {
        spanAncestor.removeStyle('color');
    
        if (!spanAncestor.getAttribute('style')?.trim()) {
          spanAncestor.removeAttribute('style');
        }
    
        if (!spanAncestor.hasAttributes()) {
          while (spanAncestor.getFirst()) {
            spanAncestor.insertBeforeMe(spanAncestor.getFirst().remove());
          }
          spanAncestor.remove();
        }
    
        return;
      }
    
      /* NEW: mixed-boundary support */
      if (splitMixedBoundarySelection(range)) {
        return;
      }
    
      /* Pass 2 – handle partially-selected spans */
      const collector = new CKEDITOR.dom.walker(range);
      collector.evaluator = node =>
        node.type === CKEDITOR.NODE_TEXT &&
        node.getAscendant(
          el => el.getName && el.getName() === 'span' && el.getStyle('color'),
          true
        );
    
      const targets = [];
      let node;
      while ((node = collector.next())) {
        targets.push(node);
      }
    
      const processedSpans = new Set();
      for (const textNode of targets) {
        const colorSpan = textNode.getAscendant(
          el => el.getName && el.getName() === 'span' && el.getStyle('color'),
          true
        );
    
        if (!colorSpan || processedSpans.has(colorSpan)) continue;
    
        const fullText = textNode.getText();
        const startOffset = textNode.equals(range.startContainer) ? range.startOffset : 0;
        const endOffset = textNode.equals(range.endContainer) ? range.endOffset : fullText.length;
    
        const before = fullText.slice(0, startOffset);
        const selected = fullText.slice(startOffset, endOffset);
        const after = fullText.slice(endOffset);
    
        const beforeFrag = before ? new CKEDITOR.dom.text(before) : null;
        const selectedFrag = selected ? new CKEDITOR.dom.text(selected) : null;
        const afterFrag = after ? new CKEDITOR.dom.text(after) : null;
    
        const chain = [];
        let current = textNode.getParent();
        while (current && !current.equals(colorSpan)) {
          chain.unshift(current);
          current = current.getParent();
        }
    
        const build = (frag, keepColor) => {
          if (!frag) return null;
    
          const wrapped = utils.wrapInside(frag, chain);
          if (!keepColor) {
            return wrapped;
          }
    
          const spanCopy = utils.clone(colorSpan);
          spanCopy.append(wrapped);
    
          return spanCopy;
        };
    
        [
          build(beforeFrag, true),
          utils.wrapInside(selectedFrag || new CKEDITOR.dom.text(''), chain),
          build(afterFrag, true)
        ]
          .filter(Boolean)
          .forEach(frag => colorSpan.insertBeforeMe(frag));
    
        textNode.remove();
    
        if (!colorSpan.getChildCount()) {
          colorSpan.remove();
        }
    
        processedSpans.add(colorSpan);
      }
    }

    /* ---------------------- UI combo ----------------------------- */
    editor.ui.addRichCombo('ApplyColor', {
      label: 'Apply Color',
      toolbar: 'styles',
      panel: {
        css: [CKEDITOR.skin.getPath('editor'), ...editor.config.contentsCss],
        multiSelect: false
      },
      init() {
        this.add('default', 'Remove Color', 'Remove Color');
        for (const [label, val] of Object.entries(colorMap)) this.add(val, label, label);
      },
      onRender() {
        this.setValue('');
      },
      onClick(choice) {
        editor.focus();
        let selection = editor.getSelection();
        if (!selection) return;

        editor.fire('lockSnapshot');
        if (choice === 'default') {
          console.log('Removing color from selection hasmik');
          // apply color to create spans if they don't exist, so that liftColorSpans can find them
          editor.applyStyle(new CKEDITOR.style({ element: 'span', styles: { color: '#fff' } }));
          selection = editor.getSelection();
          selection.getRanges().forEach(liftColorSpans);
          // remove color from fully selected spans
          selection?.getRanges().forEach(smartRemoveColorFromPartial);
        } else {
          console.log('Applying color to selection hasmik', choice);
          editor.applyStyle(new CKEDITOR.style({ element: 'span', styles: { color: choice } }));
          selection = editor.getSelection();
          selection?.getRanges().forEach(liftColorSpans);
        }

        editor.fire('unlockSnapshot');
      }
    });
  }
});
